mapper.select:
SELECT o.member_id AS memberId, ROUND(IFNULL(SUM( CASE WHEN o.status = 0 THEN 0 ELSE GREATEST(0, (IFNULL(o.total_amount, 0) - IFNULL(o.discount_amount, 0)) - IFNULL(o.real_amount, 0)) END ), 0), 2) AS totalDebt FROM sale_order o WHERE o.deleted = 0 AND o.member_id IS NOT NULL AND o.member_id IN
#{id}
GROUP BY o.member_id
